// Fetch location images from Wikimedia Commons.
// Usage:
//   node fetch-location-images.mjs              — download Barcelona (curated list)
//   node fetch-location-images.mjs barcelona    — same
//   node fetch-location-images.mjs new-york     — download a city generated by gen-city.mjs
//   node fetch-location-images.mjs all          — download all known cities
//
// Barcelona locations use pre-curated Commons filenames for reliability.
// Other cities search Commons by location name and pick the best match.

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { execFileSync } from 'child_process';
import crypto from 'crypto';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

