// ── Commons helpers ────────────────────────────────────────────────────────────
const OUTPUT_DIR = 'public/locations';
const CITIES_DIR = 'public/cities';
const UA = 'BadassQuest2ImageBot/1.0 (https://github.com/example/badass-quest-2)';

function commonsUrlFromFilename(filename) {
  const normalized = filename.replace(/ /g, '_');
  const hash = crypto.createHash('md5').update(normalized).digest('hex');
  const encoded = encodeURIComponent(normalized);
  return `https://upload.wikimedia.org/wikipedia/commons/${hash[0]}/${hash.substring(0, 2)}/${encoded}`;
}

function downloadCurl(url, dest) {
  return new Promise((resolve, reject) => {
    try {
      execFileSync('curl', [
        '-s', '-L', '-o', dest,
        '-A', UA,
        '--connect-timeout', '10',
        '--max-time', '30',
        url,
      ], { timeout: 35000 });
      resolve();
    } catch (e) {
      reject(new Error(`curl failed: ${e.message}`));
    }
  });
}

async function commonsSearch(query) {
  const url = `https://commons.wikimedia.org/w/api.php?action=query&list=search&srnamespace=6&srsearch=${encodeURIComponent(query)}&srlimit=5&format=json`;
  const res = await fetch(url, { headers: { 'User-Agent': UA } });
  if (!res.ok) throw new Error(`Commons search ${res.status}`);
  const data = await res.json();
  return (data.query?.search ?? []).map((r) => r.title.replace(/^File:/, ''));
}

async function commonsImageUrl(filename, width = 800) {
  const title = `File:${filename}`;
  const url = `https://commons.wikimedia.org/w/api.php?action=query&titles=${encodeURIComponent(title)}&prop=imageinfo&iiprop=url&iiurlwidth=${width}&format=json`;
  const res = await fetch(url, { headers: { 'User-Agent': UA } });
  if (!res.ok) throw new Error(`Commons imageinfo ${res.status}`);
  const data = await res.json();
  const pages = data.query?.pages ?? {};
  const page = Object.values(pages)[0];
  return page?.imageinfo?.[0]?.thumburl ?? null;
}

// ── Download by known filename (Barcelona) ────────────────────────────────────
async function downloadByFilename(id, filename) {
  const dest = `${OUTPUT_DIR}/${id}.jpg`;
  if (fs.existsSync(dest) && fs.statSync(dest).size > 10000) {
    console.log(`  ✓ skip  ${id}  (cached)`);
    return true;
  }
  const url = commonsUrlFromFilename(filename);
  try {
    await downloadCurl(url, dest);
    const size = fs.existsSync(dest) ? fs.statSync(dest).size : 0;
    if (size > 10000) {
      console.log(`  ✓ ${id}  ${Math.round(size / 1024)}KB`);
      return true;
    }
    if (fs.existsSync(dest)) fs.unlinkSync(dest);
    console.log(`  ✗ ${id}  too small — skipped`);
    return false;
  } catch (e) {
    console.log(`  ✗ ${id}  ${e.message}`);
    return false;
  }
}

// ── Download by searching Commons (generated cities) ─────────────────────────
async function downloadBySearch(id, name, cityName) {
  const dest = `${OUTPUT_DIR}/${id}.jpg`;
  if (fs.existsSync(dest) && fs.statSync(dest).size > 10000) {
    console.log(`  ✓ skip  ${id}  (cached)`);
    return true;
  }

  const queries = [
    `${name} ${cityName}`,
    name,
  ];

  for (const query of queries) {
    let filenames;
    try {
      filenames = await commonsSearch(query);
    } catch (e) {
      console.log(`  ✗ ${id}  search error: ${e.message}`);
      return false;
    }

    // Filter to likely image types, skip SVG/logos/maps
    const imageFiles = filenames.filter((f) =>
      /\.(jpg|jpeg|png)$/i.test(f) &&
      !/logo|map|plan|diagram|icon|coat|flag/i.test(f)
    );

    for (const filename of imageFiles) {
      let thumbUrl;
      try {
        thumbUrl = await commonsImageUrl(filename);
      } catch {
        continue;
      }
      if (!thumbUrl) continue;

      try {
        await downloadCurl(thumbUrl, dest);
        const size = fs.existsSync(dest) ? fs.statSync(dest).size : 0;
        if (size > 10000) {
          console.log(`  ✓ ${id}  ${Math.round(size / 1024)}KB  («${filename}»)`);
          return true;
        }
        if (fs.existsSync(dest)) fs.unlinkSync(dest);
      } catch {
        continue;
      }
    }
  }

  console.log(`  ✗ ${id}  no usable image found on Commons`);
  return false;
}

// ── City image ─────────────────────────────────────────────────────────────────
async function downloadCityImage(cityId, cityName) {
  const dest = `${CITIES_DIR}/${cityId}.jpg`;
  if (fs.existsSync(dest) && fs.statSync(dest).size > 10000) {
    console.log(`  ✓ skip  city/${cityId}  (cached)`);
    return;
  }
  console.log(`  Searching Commons for city image: ${cityName}…`);
  await downloadBySearch(`../cities/${cityId}`, cityName, '');
}

// ── Run a city ─────────────────────────────────────────────────────────────────
async function runCity(cityId) {
  if (cityId === 'barcelona') {
    console.log('\n=== Barcelona (curated) ===');
    let ok = 0, fail = 0;
    for (const loc of BARCELONA_LOCATIONS) {
      if (await downloadByFilename(loc.id, loc.file)) ok++; else fail++;
    }
    console.log(`Barcelona: ${ok} ok, ${fail} failed\n`);
    return;
  }

  const cacheFile = path.join(__dirname, 'scripts', '.city-cache', `${cityId}.json`);
  if (!fs.existsSync(cacheFile)) {
    console.error(`No cache file found at ${cacheFile}`);
    console.error(`Run: node scripts/gen-city.mjs ${cityId} ... first`);
    process.exit(1);
  }

  const manifest = JSON.parse(fs.readFileSync(cacheFile, 'utf8'));
  const cityName = cityId.replace(/-/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase());

  console.log(`\n=== ${cityName} (${manifest.length} locations) ===`);
  await downloadCityImage(cityId, cityName);

  let ok = 0, fail = 0;
  for (const loc of manifest) {
    if (loc.type === 'home') {
      // Use city image as home fallback — skip dedicated search
      console.log(`  — skip home (uses city image fallback)`);
      continue;
    }
    const success = await downloadBySearch(loc.id, loc.name, cityName);
    if (success) ok++; else fail++;
    // Throttle to avoid hammering Commons
    await new Promise((r) => setTimeout(r, 500));
  }
  console.log(`${cityName}: ${ok} ok, ${fail} failed\n`);
}

// ── Entry point ────────────────────────────────────────────────────────────────
async function main() {
  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
  fs.mkdirSync(CITIES_DIR, { recursive: true });

  const arg = process.argv[2] ?? 'barcelona';

  if (arg === 'all') {
    await runCity('barcelona');
    const cacheDir = path.join(__dirname, 'scripts', '.city-cache');
    if (fs.existsSync(cacheDir)) {
      for (const file of fs.readdirSync(cacheDir).filter((f) => f.endsWith('.json'))) {
        await runCity(file.replace('.json', ''));
      }
    }
  } else {
    await runCity(arg);
  }
}

main().catch((e) => { console.error(e); process.exit(1); });
